Bash(NODE_ENV=development ts-node -e "
import { energyMonitorService } from ''./src/services/energy-monitor.service'';
import { logger } from ''./src/config'';

async function test() {
  try {
    logger.info(''🧪 Testing energy monitor service...'');
    const stats = await energyMonitorService.getMonitoringStats();
    console.log(''📊 Monitoring Stats:'', JSON.stringify(stats, null, 2));

    logger.info(''🧪 Running energy monitor cycle...'');
    await energyMonitorService.monitorAndDeliverEnergy();

    logger.info(''✅ Test completed successfully'');
  } catch (error) {
    logger.error(''❌ Test failed:'', error);
  } finally {
    process.exit(0);
  }
}

test();
")

